import{c as e,Q as o,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Claude Code 的 32 个使用技巧 — 入门，进阶，高阶 — @elliotchen100","description":"","frontmatter":{"title":"Claude Code 的 32 个使用技巧 — 入门，进阶，高阶 — @elliotchen100","author":"艾略特（@elliotchen100）","date":"2026-04-29T00:00:00.000Z","source":"https://x.com/elliotchen100/status/2049299210668032393","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-29-@elliotchen100-032393.md","filePath":"research/tweets/2026-04-29-@elliotchen100-032393.md","lastUpdated":1779894392000}'),r={name:"research/tweets/2026-04-29-@elliotchen100-032393.md"};function l(i,t,p,s,d,c){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="claude-code-的-32-个使用技巧-—-入门-进阶-高阶-—-elliotchen100" tabindex="-1">Claude Code 的 32 个使用技巧 — 入门，进阶，高阶 — @elliotchen100 <a class="header-anchor" href="#claude-code-的-32-个使用技巧-—-入门-进阶-高阶-—-elliotchen100" aria-label="Permalink to &quot;Claude Code 的 32 个使用技巧 — 入门，进阶，高阶 — @elliotchen100&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/elliotchen100/status/2049299210668032393" target="_blank" rel="noreferrer">https://x.com/elliotchen100/status/2049299210668032393</a><strong>作者</strong>：艾略特（@elliotchen100） <strong>發布日期</strong>：2026-04-29 <strong>收錄日期</strong>：2026-04-29 <strong>類型</strong>：Twitter Article <strong>統計</strong>：71 likes · 9 retweets · 160 bookmarks · 14052 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>昨天看到 @nateherk 的这个 YouTube 视频，觉得很不错，推荐一下。</p><p><a href="https://www.youtube.com/watch?v=jqoFP9QapXI" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=jqoFP9QapXI</a></p><p>他的视频风格我一直挺喜欢，简简单单清清楚楚，没有废话，开头不卖关子，结尾不拖泥带水。这条尤其密集，32 个技巧塞进 16 分钟，按入门，进阶，高阶分了三档，从 /init 一路讲到 agent team。</p><p>我先把内容快速过一遍，再挑 6 个我觉得视频里讲到了但没展开，其实最关键的点，把背后的原理拆开讲。</p><h2 id="_32-个技巧速览" tabindex="-1">32 个技巧速览 <a class="header-anchor" href="#_32-个技巧速览" aria-label="Permalink to &quot;32 个技巧速览&quot;">​</a></h2><p>入门 /init 一键生成项目说明书 cloud.md plan mode 开局先规划再动手 /context 看 token 占用，超 60% 用 /compact 压缩 把 Claude 当 junior 同事，提问题不要下命令 self check 加进 todo，让它自己验自己</p><p>进阶 sub agents 并行任务，独立 context 不打架 custom skills 复用 prompt 文件 简单活丢给 Haiku 省 token 跑偏了直接 exit 重 prompt 截图喂回去做视觉 debug</p><p>高阶 /loop 自动跑 recurring tasks，最长 3 天 Git worktrees 多 session 并行 VPS 托管不掉线，手机也能远程操控 ultrathink 模式给硬骨头分配最大 token agent team 多 agent 协作分工</p><p>光看这个清单，和其他 Claude Code 教程没差别，能搜到的太多了。Nate Herk 这条视频的真正价值，是他用老手的视角把这些点串起来了。下面挑 6 个我觉得别人聊得最少，但其实最关键的，把背后的原理拆开讲。</p><h2 id="一、把-claude-当-junior-同事-不是态度问题-是-prompt-工程" tabindex="-1">一、把 Claude 当 junior 同事，不是态度问题，是 prompt 工程 <a class="header-anchor" href="#一、把-claude-当-junior-同事-不是态度问题-是-prompt-工程" aria-label="Permalink to &quot;一、把 Claude 当 junior 同事，不是态度问题，是 prompt 工程&quot;">​</a></h2><p>很多人看到这条会以为是「对它说话礼貌一点」。其实跟礼貌没关系，这是计算路径的选择。</p><p>LLM 接收命令式 prompt 时，触发的是「按指令执行」的浅层模式，直接 pattern match，输出快但思考浅。接收描述式 prompt 时，触发的是「理解后再行动」的深层模式，会展开 chain of thought，输出慢但准确度高一截。</p><p>同一个 bug，「修一下这里」和「这里看起来怪怪的，你查查为啥」出来的代码质量能差一倍。前者它就直接改你指出的那行，后者它会先去理解上下文，可能发现真正的问题在另一个地方。</p><p>更深一层，描述要具体且不带预设答案。「这里有 race condition」会让它只查 race condition，「这里偶尔会出错你查查」会让它展开完整排查。你 prompt 里预设的答案越少，激发的推理就越多。</p><h2 id="二、60-用-compact-是对抗-lost-in-the-middle-不是省-token" tabindex="-1">二、60% 用 /compact，是对抗 lost in the middle，不是省 token <a class="header-anchor" href="#二、60-用-compact-是对抗-lost-in-the-middle-不是省-token" aria-label="Permalink to &quot;二、60% 用 /compact，是对抗 lost in the middle，不是省 token&quot;">​</a></h2><p>这个 60% 经常被解读成「省 token 的阈值」。其实不是。</p><p>Stanford 2023 年有篇论文揭示了 lost in the middle 现象，LLM 在长 context 里的注意力是 U 型曲线，开头记得最牢，结尾记得最牢，中间最容易被忽略。</p><p>60% 这条线不是省钱的红线，是注意力开始衰减的经验线。超过这个点之后，你前面提过的关键需求会开始被「视而不见」，模型会犯一些「明明你说过了」的错。</p><p>/compact 真正的价值是它会保留关键决策和未完成事项，把中间的散乱讨论压掉。这不是粗暴截断，是在做注意力的重新聚焦。</p><p>判断什么时候该 compact，不要光看 token 数，要看模型是不是开始忘事。一旦它问出「你想做什么」之类的问题，立刻 compact，迟一步它就会带着错误前提继续往下做。</p><h2 id="三、跑偏了-exit-重开-是-token-经济学-不是耐心问题" tabindex="-1">三、跑偏了 exit 重开，是 token 经济学，不是耐心问题 <a class="header-anchor" href="#三、跑偏了-exit-重开-是-token-经济学-不是耐心问题" aria-label="Permalink to &quot;三、跑偏了 exit 重开，是 token 经济学，不是耐心问题&quot;">​</a></h2><p>很多人遇到 Claude 走偏，第一反应是「我再 prompt 它一下让它修正」。这个反应是错的。</p><p>被污染的 context 里，你写的修正 prompt 自己占 context，它的道歉占 context，它修正后的输出还会被错误推理影响。人类有 confirmation bias，LLM 也有，被前面的错误锚定之后很难真正跳出来。</p><p>总成本比重开高 2 到 3 倍，最终输出还可能更差。</p><p>应该建立的反射是 fail fast，看到走偏立刻 ESC，重新组织思路再 prompt，比让它自己掰回来快得多。重开不是失败，是更聪明的资源分配。</p><p>这个反射很多人建立不起来，因为觉得「重开是浪费」。其实越往后修，浪费越大。</p><h2 id="四、sub-agents-真正的价值是上下文隔离-不是并行" tabindex="-1">四、sub agents 真正的价值是上下文隔离，不是并行 <a class="header-anchor" href="#四、sub-agents-真正的价值是上下文隔离-不是并行" aria-label="Permalink to &quot;四、sub agents 真正的价值是上下文隔离，不是并行&quot;">​</a></h2><p>并行只是表象，隔离才是核心。</p><p>sub agents 把 context 从一维资源变成了树形资源。父 agent 是指挥者，看大局，不需要知道每个细节怎么实现。sub agent 是执行者，可以激进探索，包括各种失败和绕路。父 agent 只看 sub agent 的最终结论，那些失败的探索不会污染主线。</p><p>什么任务最适合开 sub agent，是「需要大量探索但只需要少量结论」的任务。比如「在 codebase 里找所有用了某个 deprecated API 的地方」，让 sub agent 把代码翻完，回来交一份清单就行。父 agent 不需要知道它翻过哪些文件，更不需要被它翻过的代码污染主上下文。</p><p>理解了这一点，你会发现很多任务都可以这样拆。「调研一下 X 库怎么用」「查一下这个 bug 在哪几个文件出现过」「列出所有需要改的测试」，全都是典型的 sub agent 任务。</p><h2 id="五、简单活给-haiku-不只是省钱-是避免「过度设计」" tabindex="-1">五、简单活给 Haiku 不只是省钱，是避免「过度设计」 <a class="header-anchor" href="#五、简单活给-haiku-不只是省钱-是避免「过度设计」" aria-label="Permalink to &quot;五、简单活给 Haiku 不只是省钱，是避免「过度设计」&quot;">​</a></h2><p>这背后是大模型的过度对齐问题。</p><p>大模型训练时见过太多复杂场景，对简单任务也会本能地加边缘情况处理，加错误处理，加注释和文档，用更复杂的设计模式。</p><p>写一个简单的 helper 函数，Sonnet 可能给你 30 行，Haiku 给你 10 行。后者在大多数场景反而更对。</p><p>我自己的判断标准是任务的「认知步骤数」：</p><p>1 到 2 步的活丢 Haiku 5 步以上留给 Sonnet 或 Opus 10 步以上才开 ultrathink</p><p>不要无脑用最强模型，最强模型对简单任务有「设计过度」的副作用，输出的代码后期还要花时间删冗余。</p><h2 id="六、-loop-挂-3-天的真正用法是-monitoring-不是写代码" tabindex="-1">六、/loop 挂 3 天的真正用法是 monitoring，不是写代码 <a class="header-anchor" href="#六、-loop-挂-3-天的真正用法是-monitoring-不是写代码" aria-label="Permalink to &quot;六、/loop 挂 3 天的真正用法是 monitoring，不是写代码&quot;">​</a></h2><p>很多人看到 /loop 第一反应是「让 Claude 连续写 3 天代码」，其实不是。</p><p>/loop 真正的用法是把 Claude 从同步工具变成异步同事。它在那挂着，定期检查状态，有事叫你。</p><p>好的 /loop 任务有几个特征：</p><p>输入是状态，不是动作 输出是「有事/没事」的判断 处理时间不连续，可以等</p><p>比如每 10 分钟看一下 CI 是不是过了，没过分析失败原因，每小时扫一下数据库慢查询，每天看一遍 PR review 队列。这些以前是「我得记得去看」的事，现在变成「Claude 看到再叫我」。</p><p>这是 Claude 从写代码工具升级成值班同事的关键。</p><h2 id="把这些串起来看" tabindex="-1">把这些串起来看 <a class="header-anchor" href="#把这些串起来看" aria-label="Permalink to &quot;把这些串起来看&quot;">​</a></h2><p>如果只看 32 个技巧，你最多能复述操作。但如果把上面这 6 个点连起来看，你会发现 Nate Herk 真正的心法，是一个心智模型：</p><p>把 Claude Code 当成一个「有限注意力，有限时间，有性格」的同事来管理，不要当成「无限算力的工具」来用。</p><p>所有技巧背后都是这个心智模型在起作用：</p><p>注意力有限，所以要做 context 管理，对应的是 /compact，/clear，sub agent 隔离 时间有限，所以要异步化，对应的是 /loop，agent team，多 session 并行 有性格，所以要 prompt 沟通，对应的是 plan mode，让它反问，junior 同事心态</p><p>心智模型一旦换过来，剩下的技巧都是延伸，自己也能想出来。</p><p>我自己用 Claude Code 写代码差不多大半年了，最大的认知升级不是某个具体技巧，而是从「我用一个工具」变成「我管一个同事」。这两种心态出来的代码质量，效率，token 消耗，差着一个数量级。</p><p>注意，此文章是我同 AI 共同创作</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：32 個技巧只是表象，核心是「把 Claude 當有限注意力/時間/性格的同事管理」這個心智模型。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>描述式 prompt &gt; 命令式 prompt</strong>：命令式觸發 pattern match 淺層模式；描述式（不預設答案）觸發 chain of thought 深層模式，準確度差一倍。</li><li><strong>60% compact 是對抗 Lost in the Middle</strong>：根據 Stanford 2023 論文，注意力呈 U 型曲線，60% 是注意力衰減的經驗線而非省 token 紅線。看到模型「忘事」立刻 compact。</li><li><strong>Fail fast 重開比修正便宜 2-3 倍</strong>：被污染的 context 中，修正 prompt 自身、模型道歉、錯誤錨定都繼續吃 token，重開反而是更聰明的資源分配。</li><li><strong>Sub agent 真正價值是 context 隔離</strong>：把 context 從一維資源變成樹形資源；父 agent 只看結論，sub agent 的探索失敗不污染主線。適合「大量探索 + 少量結論」任務。</li><li><strong>Haiku 防止 over-design</strong>：大模型過度對齊讓簡單任務也加邊界處理/錯誤處理/設計模式。判斷標準：認知步驟 1-2 步 Haiku、5+ 步 Sonnet/Opus、10+ 步才開 ultrathink。</li><li><strong>/loop 是 monitoring，不是寫程式</strong>：把 Claude 從同步工具變異步同事。好任務特徵：輸入狀態（非動作）、輸出有事/沒事判斷、處理時間不連續。</li><li><strong>統一心智模型</strong>：注意力有限 → context 管理；時間有限 → 異步化；有性格 → prompt 溝通。</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li><strong>60%</strong> context 使用率：注意力衰減經驗線</li><li><strong>2-3x</strong>：context 污染後修正的 token 成本倍數</li><li><strong>Stanford 2023</strong> Lost in the Middle 論文：U 型注意力曲線</li><li><strong>Sonnet 30 行 vs Haiku 10 行</strong>：相同 helper 函數的 over-design 對比</li><li>認知步驟分檔：<strong>1-2 / 5+ / 10+</strong> → Haiku / Sonnet+Opus / ultrathink</li><li>/loop 範例：每 10 分鐘檢查 CI、每小時掃慢查詢、每天看 PR queue</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>論點層次清晰但證據以「現象描述」為主</strong>：除 Stanford 論文外，2-3x 成本倍數、Sonnet vs Haiku 行數對比皆為作者經驗值，非實測數據。對 production 決策可作參考但需自驗證。</li><li><strong>與既有規則高度互補但有重疊</strong>：本 workspace 的 <code>context-management.md</code> 已採 30-35% 主動 compact 標準（更激進），與本文 60% 不衝突 — 60% 是「最遲」、30-35% 是「最佳」。三、四、五點原理可作為現有規則的「為什麼」補充。</li><li><strong>「junior 同事心態」對應本 workspace 的 <code>Think Before Coding</code></strong>：作者強調「描述式、不預設答案」的 prompt 觸發深度推理，這與 <code>core.md</code> 中「實作前假設顯露」屬同一現象的不同切面（一個從用戶端、一個從 Claude 端）。</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>6 個原理可直接補強 core.md / context-management.md / subagent-strategy.md 作為「為什麼」說明</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>Lost in the Middle、context 隔離 vs 並行、Haiku 防 over-design 角度比一般教學深</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>引 Stanford 論文 + 具體比例（2-3x、認知步驟 1-2/5+/10+），但多為經驗值無實測</td></tr><tr><td>D. 技術深度 (15%)</td><td>7/10</td><td>原理層（pattern match vs CoT、樹形 vs 一維 context）解釋到位，部分舉例為示意</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>「有限注意力/時間/性格」心智模型跨任務通用，6 點延伸自然</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.25/10</strong></td><td>A×0.3+B×0.2+C×0.2+D×0.15+E×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：核心是通用心智模型 + 6 個原理層說明，可直接增補現有 rules 的「為什麼」（特別是 context-management.md 的 60% 線、subagent-strategy.md 的隔離心智模型）。</p>',70)])])}const g=e(r,[["render",l]]);export{u as __pageData,g as default};
